mapper.select:
/* 피드백 조회 ForumFdbkDAO.forumFdbkList */ WITH RECURSIVE fdbk as ( SELECT a.DSCS_FDBK_ID , a.UP_DSCS_FDBK_ID , a.USER_ID , a.TEAM_ID , a.DSCS_ID , a.FDBK_CTS , a.RGTR_ID , a.FRST_INQ_DTTM , a.MDFR_ID , a.MOD_DTTM , a.DELYN , 1 AS LEVEL , CONVERT(a.DSCS_FDBK_ID, char(100)) AS PATH , a.RGTR_ID AS TO_USER_ID FROM TB_LMS_DSCS_FDBK a WHERE a.UP_DSCS_FDBK_ID IS NULL AND a.DSCS_ID = #{dscsId} UNION ALL SELECT a.DSCS_FDBK_ID , a.UP_DSCS_FDBK_ID , a.USER_ID , a.TEAM_ID , a.DSCS_ID , a.FDBK_CTS , a.RGTR_ID , a.REG_DTTM , a.MDFR_ID , a.MOD_DTTM , a.DELYN , 1+LEVEL AS LEVEL , CONCAT(b.PATH, '-', a.DSCS_FDBK_ID) AS PATH , b.RGTR_ID AS TO_USER_ID FROM TB_LMS_DSCS_FDBK a INNER JOIN fdbk b ON a.UP_DSCS_FDBK_ID = b.DSCS_FDBK_ID WHERE a.DSCS_ID = #{dscsId} ) SELECT R.* FROM (SELECT DSCS_FDBK_ID , UP_DSCS_FDBK_ID , USER_ID , TEAM_ID , DSCS_ID , FDBK_CTS , RGTR_ID , REG_DTTM , MDFR_ID , MOD_DTTM , DELYN , LEVEL , PATH , ( SELECT B.USER_ID FROM TB_LMS_USER_ACNT AS B WHERE B.USER_ID = A.RGTR_ID ) AS USER_ID , ( SELECT CASE WHEN A.RGTR_ID = '000000000000' THEN '관리자' ELSE IFNULL(USERNM, 'UnKnown') END FROM TB_LMS_USR WHERE USER_ID = A.RGTR_ID ) AS RGTRNM , RIGHT(CASE WHEN level > 2 THEN ( SELECT CASE WHEN RGTR_ID = '000000000000' THEN '관리자' ELSE IFNULL(USERNM, 'UnKnown') END FROM TB_LMS_USR WHERE USER_ID = RGTR_ID ) ELSE '' END, 2) AS USERNM , CASE WHEN LEVEL > 2 THEN ( SELECT case when TO_USER_ID = '000000000000' then '관리자' ELSE IFNULL(USERNM, 'UnKnown') END FROM TB_LMS_USR WHERE USER_ID = TO_USER_ID ) ELSE '' END AS TO_USER_NM , (SELECT COUNT(*) FROM FDBK B WHERE B.DSCS_ID = A.DSCS_ID AND B.PATH LIKE CONCAT('%', A.DSCS_FDBK_ID, '%') AND B.DELYN = 'N' AND B.DSCS_FDBK_ID != A.DSCS_FDBK_ID) AS CMNT_CNT , RIGHT(RGTR_ID,1) AS USER_ID_COLOR FROM FDBK A WHERE DSCS_ID = #{dscsId}
AND TEAM_ID=#{teamCd}
AND USER_ID = #{stdId}
) R WHERE (R.DELYN ='N' OR R.CMNT_CNT > 0) ORDER BY PATH

mapper.insert:
/*
	토론 피드백 등록
	ForumFdbkDAO.insertForumFdbk
*/
INSERT INTO TB_LMS_DSCS_FDBK (
	DSCS_FDBK_ID
	, DSCS_ID
	, USER_ID
	, UP_DSCS_FDBK_ID
	, TEAM_ID
	, FDBK_CTS
	, DELYN
	, RGTR_ID
	, REG_DTTM
	, MDFR_ID
	, MOD_DTTM
) VALUES (
	#{forumFdbkCd}
	, #{dscsId}
	, #{stdId}
	, #{parForumFdbkCd}
	, #{teamCd}
	, #{fdbkCts}
	, 'N'
	, #{rgtrId}
	, FN_DTTM()
	, #{mdfrId}
	, FN_DTTM()
)

mapper.update:
/*
	토론 피드백 수정
	ForumFdbkDAO.updateForumFdbk
*/
UPDATE TB_LMS_DSCS_FDBK SET
	  MDFR_ID = #{mdfrId}
	, MOD_DTTM = FN_DTTM()

	, UP_DSCS_FDBK_ID = #{parForumFdbkCd}


	, TEAM_ID = #{teamCd}


	, FDBK_CTS = #{fdbkCts}


	, DELYN = #{delYn}

WHERE DSCS_FDBK_ID = #{forumFdbkCd}
	AND DSCS_ID = #{dscsId}

	AND USER_ID = #{stdId}

/*
	토론 피드백 삭제
	ForumFdbkDAO.deleteForumFdbk
*/
UPDATE TB_LMS_DSCS_FDBK SET
	  MDFR_ID = #{mdfrId}
	, MOD_DTTM = FN_DTTM()
	, DELYN = 'Y'
WHERE DSCS_FDBK_ID = #{forumFdbkCd}
	AND DSCS_ID = #{dscsId}

	AND USER_ID = #{stdId}

